     1|/**
     2| * IVX Owner AI Request Orchestrator.
     3| *
     4| * Single entry point for every AI execution path in the Owner chat. Replaces
     5| * scattered direct calls to assistantReplyMutation with an explicit state machine,
     6| * synchronous checkpoint recording, and guaranteed cleanup.
     7| */
     8|
     9|import { ivxAIWatchdog } from './ivxAIWatchdog';
    10|
    11|export type AIOrchestratorState =
    12|  | 'IDLE'
    13|  | 'USER_MESSAGE_ACCEPTED'
    14|  | 'AI_TRIGGER_DECISION'
    15|  | 'AI_MUTATION_STARTED'
    16|  | 'HTTP_REQUEST_STARTED'
    17|  | 'HTTP_RESPONSE_RECEIVED'
    18|  | 'RESPONSE_PERSISTED'
    19|  | 'UI_RENDERED'
    20|  | 'SUCCESS'
    21|  | 'VALIDATION_FAILED'
    22|  | 'AUTH_FAILED'
    23|  | 'NETWORK_FAILED'
    24|  | 'PROVIDER_FAILED'
    25|  | 'TIMEOUT'
    26|  | 'CANCELLED';
    27|
    28|export interface AIOrchestratorContext {
    29|  traceId: string;
    30|  messageId: string;
    31|  conversationId: string | null;
    32|  ownerId: string | null;
    33|  mode: 'ai_only' | 'send_and_ai' | 'send_only' | 'knowledge' | 'attachment';
    34|  source: string;
    35|  state: AIOrchestratorState;
    36|  startTimeMs: number;
    37|  httpRequestStarted: boolean;
    38|  httpResponseReceived: boolean;
    39|  retryCount: number;
    40|  terminal: boolean;
    41|}
    42|
    43|export interface AIOrchestratorPayload {
    44|  text: string;
    45|  messageId: string;
    46|  traceId: string;
    47|  nonBlocking: boolean;
    48|  conversationId: string | null;
    49|  ownerId: string | null;
    50|  mode: AIOrchestratorContext['mode'];
    51|  source: string;
    52|}
    53|
    54|export interface AIOrchestratorCallbacks {
    55|  onTransition: (state: AIOrchestratorState, prev: AIOrchestratorState, ctx: AIOrchestratorContext) => void;
    56|  onExecute: (payload: AIOrchestratorPayload) => Promise<void>;
    57|  isMounted: () => boolean;
    58|  hasConversationId: () => string | null;
    59|  hasOwnerSession: () => boolean;
    60|}
    61|
    62|interface AIOrchestratorResult {
    63|  state: AIOrchestratorState;
    64|  context: AIOrchestratorContext;
    65|}
    66|
    67|export function createAIOrchestrator(callbacks: AIOrchestratorCallbacks) {
    68|  const activeRequests = new Map<string, AIOrchestratorContext>();
    69|
    70|  function transition(
    71|    ctx: AIOrchestratorContext,
    72|    next: AIOrchestratorState,
    73|    _data?: Record<string, unknown>,
    74|  ): void {
    75|    const prev = ctx.terminal ? ctx.state : (activeRequests.get(ctx.traceId)?.state ?? 'IDLE') as AIOrchestratorState;
    76|    ctx.state = next;
    77|    callbacks.onTransition(next, prev, ctx);
    78|  }
    79|
    80|  function startWatchdog(ctx: AIOrchestratorContext): void {
    81|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
    82|    if (!trace) return;
    83|    trace.pass('AI_MUTATION_STARTED', `orchestrator start mode=${ctx.mode} source=${ctx.source}`, {
    84|      messageId: ctx.messageId,
    85|      conversationId: ctx.conversationId,
    86|    });
    87|  }
    88|
    89|  function markHttpStarted(ctx: AIOrchestratorContext): void {
    90|    if (ctx.httpRequestStarted) return;
    91|    ctx.httpRequestStarted = true;
    92|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
    93|    trace?.pass('BACKEND_POST_STARTED', 'HTTP request began', { messageId: ctx.messageId });
    94|  }
    95|
    96|  function markHttpFinished(ctx: AIOrchestratorContext, status?: number): void {
    97|    ctx.httpResponseReceived = true;
    98|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
    99|    trace?.pass('BACKEND_POST_FINISHED', 'HTTP response received', { messageId: ctx.messageId, status });
   100|  }
   101|
   102|  async function execute(payload: AIOrchestratorPayload): Promise<AIOrchestratorResult> {
   103|    const ctx: AIOrchestratorContext = {
   104|      traceId: payload.traceId,
   105|      messageId: payload.messageId,
   106|      conversationId: payload.conversationId,
   107|      ownerId: payload.ownerId,
   108|      mode: payload.mode,
   109|      source: payload.source,
   110|      state: 'IDLE',
   111|      startTimeMs: Date.now(),
   112|      httpRequestStarted: false,
   113|      httpResponseReceived: false,
   114|      retryCount: 0,
   115|      terminal: false,
   116|    };
   117|
   118|    activeRequests.set(ctx.traceId, ctx);
   119|    transition(ctx, 'USER_MESSAGE_ACCEPTED');
   120|
   121|    try {
   122|      // Pre-flight checks (synchronous)
   123|      if (!callbacks.isMounted()) {
   124|        transition(ctx, 'VALIDATION_FAILED', { reason: 'component unmounted' });
   125|        return finalize(ctx, 'VALIDATION_FAILED');
   126|      }
   127|      if (!payload.text || payload.text.trim().length === 0) {
   128|        transition(ctx, 'VALIDATION_FAILED', { reason: 'empty text' });
   129|        return finalize(ctx, 'VALIDATION_FAILED');
   130|      }
   131|      if (payload.mode !== 'send_only' && !callbacks.hasOwnerSession()) {
   132|        transition(ctx, 'AUTH_FAILED', { reason: 'owner session missing' });
   133|        return finalize(ctx, 'AUTH_FAILED');
   134|      }
   135|      const conversationId = callbacks.hasConversationId();
   136|      if (payload.mode !== 'send_only' && !conversationId) {
   137|        transition(ctx, 'VALIDATION_FAILED', { reason: 'conversation id missing' });
   138|        return finalize(ctx, 'VALIDATION_FAILED');
   139|      }
   140|      if (conversationId) {
   141|        ctx.conversationId = conversationId;
   142|      }
   143|
   144|      transition(ctx, 'AI_TRIGGER_DECISION', { mode: payload.mode, source: payload.source });
   145|
   146|      if (payload.mode === 'send_only') {
   147|        transition(ctx, 'SUCCESS');
   148|        return finalize(ctx, 'SUCCESS');
   149|      }
   150|
   151|      // Synchronously mark AI_MUTATION_STARTED before any async work
   152|      transition(ctx, 'AI_MUTATION_STARTED');
   153|      startWatchdog(ctx);
   154|
   155|      // Execute the AI request (awaited, no fire-and-forget)
   156|      try {
   157|        markHttpStarted(ctx);
   158|        await callbacks.onExecute(payload);
   159|        markHttpFinished(ctx);
   160|      } catch (err) {
   161|        const error = err instanceof Error ? err : new Error(String(err));
   162|        if (error.name === 'AbortError' || error.message.toLowerCase().includes('abort')) {
   163|          transition(ctx, 'CANCELLED', { reason: error.message });
   164|          return finalize(ctx, 'CANCELLED');
   165|        }
   166|        if (!ctx.httpRequestStarted) {
   167|          transition(ctx, 'NETWORK_FAILED', { reason: error.message });
   168|          return finalize(ctx, 'NETWORK_FAILED');
   169|        }
   170|        if (!ctx.httpResponseReceived) {
   171|          transition(ctx, 'TIMEOUT', { reason: error.message });
   172|          return finalize(ctx, 'TIMEOUT');
   173|        }
   174|        transition(ctx, 'PROVIDER_FAILED', { reason: error.message });
   175|        return finalize(ctx, 'PROVIDER_FAILED');
   176|      }
   177|
   178|      transition(ctx, 'RESPONSE_PERSISTED');
   179|      transition(ctx, 'UI_RENDERED');
   180|      transition(ctx, 'SUCCESS');
   181|      return finalize(ctx, 'SUCCESS');
   182|    } catch (unexpected) {
   183|      const error = unexpected instanceof Error ? unexpected : new Error(String(unexpected));
   184|      transition(ctx, 'PROVIDER_FAILED', { reason: error.message });
   185|      return finalize(ctx, 'PROVIDER_FAILED');
   186|    }
   187|  }
   188|
   189|  function finalize(ctx: AIOrchestratorContext, terminal: AIOrchestratorState): AIOrchestratorResult {
   190|    ctx.terminal = true;
   191|    ctx.state = terminal;
   192|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
   193|    if (terminal === 'SUCCESS') {
   194|      trace?.complete('SUCCESS');
   195|    } else {
   196|      trace?.fail(ctx.httpRequestStarted ? 'BACKEND_POST_FINISHED' : 'AI_MUTATION_STARTED', `terminal=${terminal}`);
   197|    }
   198|    activeRequests.delete(ctx.traceId);
   199|    return { state: terminal, context: ctx };
   200|  }
   201|
   202|  function cancel(traceId: string): void {
   203|    const ctx = activeRequests.get(traceId);
   204|    if (!ctx || ctx.terminal) return;
   205|    transition(ctx, 'CANCELLED');
   206|    finalize(ctx, 'CANCELLED');
   207|  }
   208|
   209|  return {
   210|    execute,
   211|    cancel,
   212|    markHttpStarted,
   213|    markHttpFinished,
   214|    getContext: (traceId: string) => activeRequests.get(traceId),
   215|  };
   216|}
   217|
   218|export type AIOrchestrator = ReturnType<typeof createAIOrchestrator>;

