     1|/**
     2| * Runtime-free client-side classifier for the LATEST owner message.
     3| *
     4| * The owner-gated `/api/ivx/owner-ai` route runs the BLOCK 28 intent router
     5| * (exact-echo + execution/task-block detection) server-side. But when the
     6| * in-app owner session is not privileged the owner route returns 401/403 and
     7| * the client recovers via the no-auth `/public/chat` generic deal-intelligence
     8| * engine (BLOCK 13). That generic engine CANNOT execute tasks, run the intent
     9| * router, or echo verbatim — so a task command answered via the fallback comes
    10| * back as an unrelated generic deal answer ("fake chat that doesn't match my
    11| * request").
    12| *
    13| * This module mirrors the two backend detectors so the client can recognise
    14| * those command classes BEFORE handing them to the generic fallback and avoid
    15| * the mismatch. It has ZERO runtime imports so it stays unit-testable without
    16| * the app bundle, Supabase, or the network.
    17| *
    18| * Source of truth (kept in sync): `backend/services/ivx-owner-ai-intent-router.ts`
    19| *   - `resolveExactEchoCommand`
    20| *   - `isOwnerExecutionOrTaskBlock`
    21| */
    22|
    23|function normalizePrompt(prompt: string): string {
    24|  return prompt.trim().toLowerCase().replace(/\s+/g, ' ');
    25|}
    26|
    27|/**
    28| * Deterministic exact-echo command detector (BLOCK 28 acceptance test B).
    29| * Returns the exact payload to echo VERBATIM (original casing preserved), or null.
    30| */
    31|export function resolveExactEchoCommand(prompt: string): string | null {
    32|  const raw = prompt.trim();
    33|  if (!raw) {
    34|    return null;
    35|  }
    36|  const match = raw.match(
    37|    /^(?:please\s+)?(?:reply|respond|answer|say|repeat|echo|output|return|print)\s+(?:back\s+)?exactly(?:\s+with)?\s*[:\-]?\s*([\s\S]+)$/i,
    38|  );
    39|  if (!match) {
    40|    return null;
    41|  }
    42|  let payload = match[1].trim();
    43|  const quoted = payload.match(/^(["'\u201c\u2018])([\s\S]+)(["'\u201d\u2019])$/);
    44|  if (quoted) {
    45|    payload = quoted[2].trim();
    46|  }
    47|  return payload.length > 0 ? payload : null;
    48|}
    49|
    50|/**
    51| * Detects a long, structured owner EXECUTION command or task block (e.g.
    52| * "BLOCK 28 Visitor-to-Investor Conversion Engine / Create: ... / Track: ...").
    53| * These must NEVER be answered by the generic /public/chat fallback, which
    54| * cannot execute them and produces an unrelated generic reply.
    55| */
    56|export function isOwnerExecutionOrTaskBlock(prompt: string): boolean {
    57|  const raw = prompt.trim();
    58|  if (!raw) {
    59|    return false;
    60|  }
    61|  const normalized = normalizePrompt(prompt);
    62|
    63|  if (/\b(block|step|phase)\s*\d+\b/.test(normalized)) {
    64|    return true;
    65|  }
    66|
    67|  const specMarkerCount = (raw.match(
    68|    /^\s*(create|track|stages?|capabilities|dashboard|requirements?|safety|store|return|show|build|objective|audit|capabilities?|metrics?)\s*:/gim,
    69|  ) ?? []).length;
    70|  if (specMarkerCount >= 2) {
    71|    return true;
    72|  }
    73|
    74|  const lineCount = raw.split(/\n/).filter((line) => line.trim().length > 0).length;
    75|  if (raw.length >= 320 && lineCount >= 4) {
    76|    return true;
    77|  }
    78|
    79|  if (
    80|    raw.length >= 90
    81|    && /\b(engine|system|pipeline|module|platform|dashboard|workflow)\b/.test(normalized)
    82|    && /\b(create|build|implement|add|wire|ship|deploy|design|develop)\b/.test(normalized)
    83|  ) {
    84|    return true;
    85|  }
    86|
    87|  return false;
    88|}
    89|
    90|export type OwnerCommandClass = 'exact_echo' | 'execution_task_block' | 'conversational';
    91|
    92|export type OwnerCommandClassification = {
    93|  commandClass: OwnerCommandClass;
    94|  /** Verbatim payload for exact-echo commands, else null. */
    95|  echoPayload: string | null;
    96|  /**
    97|   * True when the generic /public/chat fallback would produce a mismatched
    98|   * answer for this message (exact-echo or execution/task block) and must NOT
    99|   * be used as-is.
   100|   */
   101|  requiresPrivilegedExecution: boolean;
   102|};
   103|
   104|/**
   105| * Classify the LATEST owner message into the command class that determines
   106| * whether the generic /public/chat fallback is appropriate.
   107| */
   108|export function classifyLatestOwnerCommand(message: string): OwnerCommandClassification {
   109|  const echoPayload = resolveExactEchoCommand(message);
   110|  if (echoPayload !== null) {
   111|    return { commandClass: 'exact_echo', echoPayload, requiresPrivilegedExecution: true };
   112|  }
   113|  if (isOwnerExecutionOrTaskBlock(message)) {
   114|    return { commandClass: 'execution_task_block', echoPayload: null, requiresPrivilegedExecution: true };
   115|  }
   116|  return { commandClass: 'conversational', echoPayload: null, requiresPrivilegedExecution: false };
   117|}

