     1|/**
     2| * IVX self-hosted Senior Developer Worker client (owner-gated).
     3| *
     4| * Submits owner-approved build/development jobs to the self-hosted worker and
     5| * tracks them WITHOUT Rork as the executor:
     6| *   - POST /api/ivx/senior-developer/worker/jobs   → submit a job
     7| *   - GET  /api/ivx/senior-developer/worker/jobs/:jobId → poll one job
     8| *   - GET  /api/ivx/worker-last-proof              → compact last-proof
     9| *   - GET  /api/ivx/senior-developer/worker/status → worker availability
    10| *
    11| * Sends only the logged-in Supabase owner session bearer. Secrets stay
    12| * server-side. Never fabricates a commit hash, deploy id, or health result —
    13| * every value comes from the live owner-gated worker API.
    14| */
    15|import { getIVXOwnerAIConfigAudit } from '@/lib/ivx-supabase-client';
    16|import { supabase } from '@/lib/supabase';
    17|import type { SeniorDeveloperJobDraft } from './seniorDeveloperBuildIntent';
    18|
    19|/** Stable status codes surfaced to the chat for non-success outcomes. */
    20|export type WorkerSubmitStatusCode =
    21|  | 'OWNER_APPROVAL_REQUIRED'
    22|  | 'WORKER_UNAVAILABLE'
    23|  | 'DEPLOY_SECRETS_MISSING'
    24|  | 'SUBMITTED';
    25|
    26|export type WorkerJobFinalStatus = 'COMPLETE' | 'LOCAL_ONLY' | 'BLOCKED' | 'FAILED' | 'RUNNING';
    27|
    28|export type WorkerJobResultSummary = {
    29|  jobId: string;
    30|  finalStatus: WorkerJobFinalStatus;
    31|  commitSha: string | null;
    32|  deployId: string | null;
    33|  deployStatus: string | null;
    34|  healthStatus: number | null;
    35|  healthOk: boolean;
    36|  commitMatch: boolean;
    37|  changedFiles: string[];
    38|  testsRun: boolean;
    39|  testsPassed: boolean;
    40|  typecheckRun: boolean;
    41|  buildRun: boolean;
    42|  error: string | null;
    43|};
    44|
    45|export type WorkerJobView = {
    46|  jobId: string;
    47|  status: 'queued' | 'running' | 'completed' | 'failed' | 'blocked';
    48|  finishedAt: string | null;
    49|  result: WorkerJobResultSummary | null;
    50|  error: string | null;
    51|};
    52|
    53|export type WorkerLastProof = {
    54|  lastJobId: string | null;
    55|  lastCommitHash: string | null;
    56|  lastDeployId: string | null;
    57|  lastHealthStatus: number | null;
    58|  lastVersionMatch: boolean;
    59|  completedAt: string | null;
    60|};
    61|
    62|function isRecord(value: unknown): value is Record<string, unknown> {
    63|  return !!value && typeof value === 'object' && !Array.isArray(value);
    64|}
    65|
    66|function readString(value: unknown): string | null {
    67|  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;
    68|}
    69|
    70|function readNumber(value: unknown): number | null {
    71|  return typeof value === 'number' && Number.isFinite(value) ? value : null;
    72|}
    73|
    74|function readBool(value: unknown): boolean {
    75|  return value === true;
    76|}
    77|
    78|function readStringArray(value: unknown): string[] {
    79|  if (!Array.isArray(value)) return [];
    80|  return value.map((item) => readString(item)).filter((item): item is string => item !== null).slice(0, 25);
    81|}
    82|
    83|function buildWorkerUrls(suffix: string): string[] {
    84|  const audit = getIVXOwnerAIConfigAudit();
    85|  const urls: string[] = [];
    86|  const push = (raw: string | null | undefined): void => {
    87|    const trimmed = raw?.trim();
    88|    if (!trimmed || urls.includes(trimmed)) return;
    89|    urls.push(trimmed);
    90|  };
    91|  const pushFromBase = (baseUrl: string | null | undefined): void => {
    92|    const base = baseUrl?.trim().replace(/\/+$/, '');
    93|    if (!base) return;
    94|    push(`${base}${suffix}`);
    95|  };
    96|  pushFromBase(audit.activeBaseUrl);
    97|  for (const endpoint of audit.candidateEndpoints) {
    98|    const normalized = endpoint.replace(/\/+$/, '');
    99|    if (normalized.endsWith('/api/ivx/owner-ai')) {
   100|      pushFromBase(normalized.slice(0, -'/api/ivx/owner-ai'.length));
   101|    } else if (normalized.endsWith('/ivx/owner-ai')) {
   102|      pushFromBase(normalized.slice(0, -'/ivx/owner-ai'.length));
   103|    }
   104|  }
   105|  return urls;
   106|}
   107|
   108|async function getOwnerBearer(): Promise<string | null> {
   109|  try {
   110|    const { data } = await supabase.auth.getSession();
   111|    const token = data.session?.access_token ?? '';
   112|    return token.length > 0 && token.split('.').length === 3 ? token : null;
   113|  } catch {
   114|    return null;
   115|  }
   116|}
   117|
   118|async function readJson(response: Response): Promise<Record<string, unknown>> {
   119|  const text = await response.text();
   120|  if (!text) return {};
   121|  try {
   122|    const parsed = JSON.parse(text) as unknown;
   123|    return isRecord(parsed) ? parsed : { value: parsed };
   124|  } catch {
   125|    return { raw: text.slice(0, 500) };
   126|  }
   127|}
   128|
   129|type WorkerFetchResult = { ok: boolean; httpStatus: number; payload: Record<string, unknown> };
   130|
   131|async function workerFetch(suffix: string, init: RequestInit): Promise<WorkerFetchResult> {
   132|  const token = await getOwnerBearer();
   133|  if (!token) {
   134|    return { ok: false, httpStatus: 401, payload: { error: 'OWNER_APPROVAL_REQUIRED', ownerOnly: true } };
   135|  }
   136|  const urls = buildWorkerUrls(suffix);
   137|  if (urls.length === 0) {
   138|    return { ok: false, httpStatus: 0, payload: { error: 'WORKER_UNAVAILABLE' } };
   139|  }
   140|  let last: WorkerFetchResult | null = null;
   141|  for (const url of urls) {
   142|    try {
   143|      const response = await fetch(url, {
   144|        ...init,
   145|        headers: {
   146|          Accept: 'application/json',
   147|          'Content-Type': 'application/json',
   148|          Authorization: `Bearer ${token}`,
   149|          ...(init.headers ?? {}),
   150|        },
   151|      });
   152|      const payload = await readJson(response);
   153|      last = { ok: response.ok, httpStatus: response.status, payload };
   154|      if (response.ok) return last;
   155|    } catch (error) {
   156|      last = { ok: false, httpStatus: 0, payload: { error: error instanceof Error ? error.message : 'WORKER_UNAVAILABLE' } };
   157|    }
   158|  }
   159|  return last ?? { ok: false, httpStatus: 0, payload: { error: 'WORKER_UNAVAILABLE' } };
   160|}
   161|
   162|function mapResultSummary(value: unknown, jobId: string): WorkerJobResultSummary | null {
   163|  if (!isRecord(value)) return null;
   164|  const finalStatusRaw = readString(value.finalStatus);
   165|  const finalStatus: WorkerJobFinalStatus =
   166|    finalStatusRaw === 'COMPLETE' || finalStatusRaw === 'LOCAL_ONLY' || finalStatusRaw === 'BLOCKED' || finalStatusRaw === 'FAILED'
   167|      ? finalStatusRaw
   168|      : 'RUNNING';
   169|  return {
   170|    jobId,
   171|    finalStatus,
   172|    commitSha: readString(value.commitSha),
   173|    deployId: readString(value.deployId),
   174|    deployStatus: readString(value.deployStatus),
   175|    healthStatus: readNumber(value.healthStatus),
   176|    healthOk: readBool(value.healthOk),
   177|    commitMatch: readBool(value.commitMatch),
   178|    changedFiles: readStringArray(value.changedFiles),
   179|    testsRun: readBool(value.testsRun),
   180|    testsPassed: readBool(value.testsPassed),
   181|    typecheckRun: readBool(value.typecheckRun),
   182|    buildRun: readBool(value.buildRun),
   183|    error: readString(value.error),
   184|  };
   185|}
   186|
   187|function mapJob(payload: Record<string, unknown>): WorkerJobView | null {
   188|  const job = isRecord(payload.job) ? payload.job : null;
   189|  if (!job) return null;
   190|  const jobId = readString(job.jobId) ?? '';
   191|  const statusRaw = readString(job.status) ?? 'queued';
   192|  const status: WorkerJobView['status'] =
   193|    statusRaw === 'running' || statusRaw === 'completed' || statusRaw === 'failed' || statusRaw === 'blocked'
   194|      ? statusRaw
   195|      : 'queued';
   196|  return {
   197|    jobId,
   198|    status,
   199|    finishedAt: readString(job.finishedAt),
   200|    result: mapResultSummary(job.result, jobId),
   201|    error: readString(job.error),
   202|  };
   203|}
   204|
   205|export type WorkerSubmitResult = {
   206|  statusCode: WorkerSubmitStatusCode;
   207|  jobId: string | null;
   208|  pollPath: string | null;
   209|  reason: string | null;
   210|};
   211|
   212|/**
   213| * Submit an owner-approved build job to the worker. Maps owner/secret/worker
   214| * failures to stable status codes so the chat can render the right card.
